UPDATE public.questions SET
  stimulus_text = 'The first time I tried to make a pie crust, I was so overwhelmed by the instructions that I gave up before I even started.  I thought that baking was supposed to be relaxing, but it seemed like every step required precision and skill.  Why did the instructions make the author feel overwhelmed? Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
